integer i, j;
always @(i, j) $display("[%0t] B %0d %0d", $time, i, j);
initial begin
  for(i = 1; i < 3; i = i + 1)
    for(j = 6; j < 8; j = j + 1) #1 $display("[%0t] A %0d %0d", $time, i, j);
end

integer i, j;
initial begin
  for(i = 1; i < 3; i = i + 1)
    for(j = 6; j < 8; j = j + 1) begin
      $display("[%0t] A %0d %0d", $time, i, j);
      #1;
      $display("[%0t] C %0d %0d", $time, i, j);
    end
end

integer i, j;
always @(i, j) $display("%0d %0d", i, j);
initial begin
  for(i = 1; i < 3; i = i + 1)
    for(j = 6; j < 8; j = j + 1) #1;
end
